import { ethers } from 'ethers';
import * as fs from 'fs';
import * as path from 'path';

const BNB_TESTNET_RPC = 'https://data-seed-prebsc-1-s1.binance.org:8545';

const CONTRACT_BYTECODE = "";

async function deploy() {
  const provider = new ethers.JsonRpcProvider(BNB_TESTNET_RPC, {
    chainId: 97,
    name: 'bnb-testnet',
  });

  const privateKey = process.env.WALLET_PRIVATE_KEY;
  if (!privateKey) {
    console.error('WALLET_PRIVATE_KEY not set');
    process.exit(1);
  }

  const wallet = new ethers.Wallet(privateKey, provider);
  console.log('Deploying from:', wallet.address);

  const balance = await provider.getBalance(wallet.address);
  console.log('Balance:', ethers.formatEther(balance), 'BNB');

  if (balance === 0n) {
    console.error('No BNB balance. Get testnet BNB first.');
    process.exit(1);
  }

  console.log('Deploying contract...');

  const factory = new ethers.ContractFactory(
    ["constructor()"],
    CONTRACT_BYTECODE,
    wallet
  );

  const contract = await factory.deploy({ gasLimit: 3000000n });
  await contract.waitForDeployment();

  const address = await contract.getAddress();
  console.log('Contract deployed at:', address);
  console.log('Add this to your .env.local:');
  console.log('NFT_CONTRACT_ADDRESS=' + address);
}

deploy().catch(console.error);